sql:
SELECT AVG(address_count) AS average_address_count
FROM (
    SELECT administrative_unit_level_1, COUNT(address_id) AS address_count
    FROM addresses
    GROUP BY administrative_unit_level_1
);

SELECT unit_name
FROM administrative_unit_levels_1
WHERE iso_code = 'USA';

external_knowledge:
- The specific role and context are determined by the parameters '<user_role>' and '<usage_context>'; 
- A user's role may be 'admin', 'manager', or 'user', which determines their level of access and permissions; 
- The usage context might include 'home', 'work', or 'billing', indicating the purpose or location associated with the address.

sql:
SELECT validation_id, address_id, validation_message
FROM address_validation
WHERE is_valid = 0;

SELECT address_id, COUNT(usage_id) AS total_usage
FROM address_usage
GROUP BY address_id;

SELECT COUNT(*) AS validated_count 
FROM address_validation 
WHERE strftime('%Y-%m', validation_date) = 'YYYY-MM';

SELECT *
FROM address_codelists
WHERE codelist_name = 'ISO 3166-1';
